" OData request with pagination (auto-generated by Fiori):
" GET /SalesOrder?$top=25&$skip=0&$orderby=OrderDate desc
" Next page:
" GET /SalesOrder?$top=25&$skip=25&$orderby=OrderDate desc

" Correct CDS annotations for performance:
@AbapCatalog.sqlViewName: 'ZV_SALESORD'
@AbapCatalog.compiler.compareFilter: true  " <- push filter to DB
@AbapCatalog.preserveKey: true             " <- preserve keys for joins
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Sales Order'
define root view entity ZI_SalesOrder
  as select from zsales_order
{
  key order_id    as OrderId,
      customer_id as CustomerId,
      status      as Status,
      order_date  as OrderDate
}
" With compareFilter: true — WHERE status='OPEN' goes to DB
" Without: all rows fetched, ABAP filters — 100x slower on large tables

" DCL File: ZI_SalesOrder.dcl
@EndUserText.label: 'Sales Order DCL'
@MappingRole: true
define role ZI_SalesOrder {
  grant select on ZI_SalesOrder
    where ( SalesOrg ) =
      aspect pfcg_auth( V_VBAK_VKO,  " Auth object
                        VKORG,        " Field in auth object
                        ACTVT = '03' );  " Activity: display
}
" Result: User sees ONLY SalesOrders where their role
" has authorization for that SalesOrg value in V_VBAK_VKO

" CDS View - enable DCL check:
@AccessControl.authorizationCheck: #CHECK  " <- DCL evaluated
define root view entity ZI_SalesOrder
  as select from zsales_order
{ key order_id as OrderId, sales_org as SalesOrg, ... }
